Chef defined amazingness of a number **n** as follows. Let array **a** denote the decimal representation of **n**.
amazingness of **n** is defined by following pseudo code.


`
amazingness(a)
{
    set **s**;
    int ans = 0;
    for ( int i = 0; i &lt; a.length(); i++ ) {
         int val = 0;
         for ( int j = i; j &lt; a.length(); j++ ) {
            val ^= a[j];  
            // a[j] denotes digit at j-th (0-based indexing) position of **n** counting 
 from most signficant digit (left to right).
            if (val not present in set s before) {
                 ans += val;
                 add val to set **s**
            }
         }
   }
   return ans;
}
`


Given two integers **L, R**. Find out the following sum : amazingness**L** + amazingness**L + 1** + ... + amazingness**R**. As the answer could be large, print your answer modulo **109 + 7 (1000000007)**

code.C:
// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007

int calculateAmazingness(long long num) {
    int len = 0;
    long long temp = num;
    while (temp > 0) {
        len++;
        temp /= 10;
    }
    int* digits = (int*)malloc(len * sizeof(int));
    for (int i = len - 1; i >= 0; i--) {
        digits[i] = num % 10;
        num /= 10;
    }
    int amazingness = 0;
    for (int i = 0; i < len; i++) {
        int val = 0;
        for (int j = i; j < len; j++) {
            val ^= digits[j];
            int found = 0;
            for (int k = 0; k < i; k++) {
                if (val == amazingness) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                amazingness += val;
                amazingness %= MOD;
            }
        }
    }
    free(digits);
    return amazingness;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long L, R;
        scanf("%lld %lld", &L, &R);
        long long sum = 0;
        for (long long i = L; i <= R; i++) {
            sum += calculateAmazingness(i);
            sum %= MOD;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

