// COMPLETE, COMPILABLE C++ code
#include <iostream>
#include <vector>
#include <set>
#include <string>
using namespace std;
#define MOD 1000000007

int calculateAmazingness(long long num) {
    string str = to_string(num);
    int amazingness = 0;
    set<int> uniqueVals;
    for (int i = 0; i < str.size(); i++) {
        int val = 0;
        for (int j = i; j < str.size(); j++) {
            val ^= str[j] - '0';
            if (uniqueVals.find(val) == uniqueVals.end()) {
                amazingness += val;
                amazingness %= MOD;
                uniqueVals.insert(val);
            }
        }
    }
    return amazingness;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        long long L, R;
        cin >> L >> R;
        long long sum = 0;
        for (long long i = L; i <= R; i++) {
            sum += calculateAmazingness(i);
            sum %= MOD;
        }
        cout << sum << endl;
    }
    return 0;
}

code.Java:
// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
import java.util.HashSet;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long L = sc.nextLong();
            long R = sc.nextLong();
            long sum = 0;
            for (long i = L; i <= R; i++) {
                sum += calculateAmazingness(i);
                sum %= 1000000007;
            }
            System.out.println(sum);
        }
    }

    public static long calculateAmazingness(long num) {
        String str = Long.toString(num);
        long amazingness = 0;
        HashSet<Integer> uniqueVals = new HashSet<>();
        for (int i = 0; i < str.length(); i++) {
            int val = 0;
            for (int j = i; j < str.length(); j++) {
                val ^= str.charAt(j) - '0';
                if (!uniqueVals.contains(val)) {
                    amazingness += val;
                    amazingness %= 1000000007;
                    uniqueVals.add(val);
                }
            }
        }
        return amazingness;
    }
}

