// COMPLETE, RUNNABLE JavaScript code
const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;

function calculateAmazingness(num) {
    const str = num.toString();
    let amazingness = 0;
    const uniqueVals = new Set();
    for (let i = 0; i < str.length; i++) {
        let val = 0;
        for (let j = i; j < str.length; j++) {
            val ^= parseInt(str[j]);
            if (!uniqueVals.has(val)) {
                amazingness += val;
                amazingness %= MOD;
                uniqueVals.add(val);
            }
        }
    }
    return amazingness;
}

const T = parseInt(input[idx++]);
for (let i = 0; i < T; i++) {
    const [L, R] = input[idx++].split(' ').map(Number);
    let sum = 0;
    for (let j = L; j <= R; j++) {
        sum += calculateAmazingness(j);
        sum %= MOD;
    }
    console.log(sum);
}

